parameters.text:
=Write a NEW, DIFFERENT LinkedIn post based on this article. And It Should Be Different than last draft 
Title: {{$json.title}} 
Summary: {{$json.summary}}
Last Draft: {{ $json.draft_content }}

parameters.jsCode:
let rawText = $input.item.json.output || "";

// 1. Strip markdown code blocks
if (rawText.includes('```json')) rawText = rawText.split('```json')[1].split('```')[0];
else if (rawText.includes('```')) rawText = rawText.split('```')[1].split('```')[0];

rawText = rawText.trim();

try {
  // Attempt 1: Standard parse
  let safeText = rawText.replace(/\n/g, "\\n").replace(/\r/g, "\\r");
  let parsed = JSON.parse(safeText);
  return { linkedin_post: parsed.linkedin_post };
} catch (e) {
  // Attempt 2 (The Titanium Hammer): Aggressive String Extraction

  // Strip the opening JSON keys and quotes
  let cleanText = rawText.replace(/^[\s\S]*?"linkedin_post"\s*:\s*"/, '');

  // THE MAGIC FIX: Vacuum up ANY combination of trailing quotes, spaces, newlines, or braces at the very end
  cleanText = cleanText.replace(/["\s}\]]+$/, '');

  // Un-escape any quotes or newlines the LLM tried to format
  cleanText = cleanText.replace(/\\"/g, '"');
  cleanText = cleanText.replace(/\\n/g, '\n');

  return { linkedin_post: cleanText.trim() };
}

parameters.query:
UPDATE content_pipeline 
SET draft_content = '{{ $json.linkedin_post.replace(/'/g, "''") }}'
WHERE id = '{{ $('Switch').item.json.article_id }}';

parameters.jsCode:
// Parse the stringified payload from Slack
const payload = JSON.parse($input.item.json.body.payload);

return {
  action: payload.actions[0].action_id, // e.g., 'approve_post'
  article_id: payload.actions[0].value, // The DB ID we hid in the button
  user: payload.user.username,
  message_ts: payload.container.message_ts, // Needed to update the Slack message later
  channel_id: payload.container.channel_id
};

